using System.Text;

namespace MTConnect.NET_DocsGen;

/// <summary>
/// Markdown for `docs/reference/index.md` — the landing page for the
/// auto-generated reference section.
/// </summary>
public static class IndexRenderer
{
    public const string AutoGenMarker = "<!-- AUTO-GENERATED by build/MTConnect.NET-DocsGen — do not edit by hand. -->";

    public static string Render()
    {
        var sb = new StringBuilder();
        sb.AppendLine(AutoGenMarker);
        sb.AppendLine();
        sb.AppendLine("# Auto-generated reference");
        sb.AppendLine();
        sb.AppendLine("Every page in this section is produced by `build/MTConnect.NET-DocsGen` at docs-build time by inspecting the source tree with Roslyn. Editing these files by hand will be overwritten on the next regeneration; instead, edit the source and re-run:");
        sb.AppendLine();
        sb.AppendLine("```bash");
        sb.AppendLine("dotnet run --project build/MTConnect.NET-DocsGen -- --repo .");
        sb.AppendLine("```");
        sb.AppendLine();
        sb.AppendLine("## Pages");
        sb.AppendLine();
        sb.AppendLine("- [HTTP API endpoints](./http-api)");
        sb.AppendLine("- [Environment variables](./environment-variables)");
        sb.AppendLine("- [Configuration schema](./configuration)");
        sb.AppendLine();
        sb.AppendLine("## Validation");
        sb.AppendLine();
        sb.AppendLine("`MTConnect.NET-Docs-Tests` includes a `DocsReferenceGenerationTests` fixture that re-runs the same Roslyn / shell inventories and asserts the on-disk markdown is in sync. Adding an HTTP route, a `Environment.GetEnvironmentVariable(\"…\")` read, a `${MTCONNECT_…}` reference in a contributor script, or a configuration property without regenerating the reference therefore fails CI.");
        sb.AppendLine();
        return sb.ToString();
    }
}

/// <summary>
/// Markdown for `docs/reference/http-api.md`.
/// </summary>
public static class HttpApiRenderer
{
    public static string Render(IReadOnlyList<EndpointInfo> endpoints)
    {
        var sb = new StringBuilder();
        sb.AppendLine(IndexRenderer.AutoGenMarker);
        sb.AppendLine();
        sb.AppendLine("# HTTP API reference");
        sb.AppendLine();
        sb.AppendLine("This page lists every HTTP endpoint exposed by an MTConnect.NET agent, separated by the underlying transport implementation. The list is generated by walking the source tree with Roslyn and does not require any project to compile — including `MTConnect.NET-HTTP-AspNetCore`, which currently fails to build on `net8.0` (see `extra-files.user/spec/` for the porting issue) and is documented here statically.");
        sb.AppendLine();
        sb.AppendLine("## Surface taxonomy");
        sb.AppendLine();
        sb.AppendLine("- **Agent API** — the MTConnect-Standard request types (`/probe`, `/current`, `/sample`, `/assets`, `/asset/{id}`, and the per-device variants of the same). Every endpoint listed below currently belongs to this surface.");
        sb.AppendLine("- **Admin / diagnostic** — none. No administrative endpoint is currently exposed by either transport. A search for `/admin`, `/diagnostics`, `/metrics`, or `/health` across the source tree returns no hits.");
        sb.AppendLine();
        sb.AppendLine("## Ceen transport (`MTConnect.NET-HTTP`)");
        sb.AppendLine();
        sb.AppendLine("Routes are registered inside `MTConnectHttpServer.ConfigureServer` and dispatched by the bundled Ceen router.");
        sb.AppendLine();
        RenderTable(sb, endpoints.Where(e => e.Source == "Ceen"));

        sb.AppendLine();
        sb.AppendLine("## AspNetCore transport (`MTConnect.NET-HTTP-AspNetCore`)");
        sb.AppendLine();
        sb.AppendLine("Routes are declared on `[ApiController]` types under `Http/Controllers/`. The project does not currently build on `net8.0`, so this section is generated by static Roslyn inspection and will track any future controller changes regardless of build state.");
        sb.AppendLine();
        RenderTable(sb, endpoints.Where(e => e.Source == "AspNetCore"));

        sb.AppendLine();
        sb.AppendLine("## Per-endpoint detail");
        sb.AppendLine();
        foreach (var e in endpoints)
        {
            sb.AppendLine($"### `{e.Method} {e.PathTemplate}` &mdash; {e.Source}");
            sb.AppendLine();
            sb.AppendLine($"- **Handler**: `{e.Handler}`");
            sb.AppendLine($"- **Surface**: {e.Surface}");
            sb.AppendLine($"- **Source**: [`{e.FileRelativePath}:{e.Line}`](https://github.com/TrakHound/MTConnect.NET/blob/master/{e.FileRelativePath}#L{e.Line})");
            if (e.ResponseStatusCodes.Count > 0)
            {
                sb.AppendLine($"- **Response status codes**: {string.Join(", ", e.ResponseStatusCodes)}");
            }
            sb.AppendLine();
            if (!string.IsNullOrEmpty(e.Summary))
            {
                sb.AppendLine(e.Summary);
                sb.AppendLine();
            }
            if (e.Parameters.Count > 0)
            {
                sb.AppendLine("**Parameters**");
                sb.AppendLine();
                sb.AppendLine("| Name | Kind | Type | Default | Description |");
                sb.AppendLine("| --- | --- | --- | --- | --- |");
                foreach (var p in e.Parameters)
                {
                    sb.AppendLine($"| `{p.Name}` | {p.Kind} | `{EscapeCell(p.Type)}` | {EscapeCell(p.DefaultValue ?? string.Empty)} | {EscapeCell(p.Summary)} |");
                }
                sb.AppendLine();
            }
        }

        return sb.ToString();
    }

    private static void RenderTable(StringBuilder sb, IEnumerable<EndpointInfo> rows)
    {
        var list = rows.ToList();
        if (list.Count == 0)
        {
            sb.AppendLine("_No endpoints discovered._");
            sb.AppendLine();
            return;
        }
        sb.AppendLine("| Method | Path | Handler | Source |");
        sb.AppendLine("| --- | --- | --- | --- |");
        foreach (var e in list)
        {
            sb.AppendLine($"| `{e.Method}` | `{e.PathTemplate}` | `{e.Handler}` | `{e.FileRelativePath}:{e.Line}` |");
        }
    }

    private static string EscapeCell(string s) => s.Replace("|", "\\|").Replace("\n", " ").Replace("\r", " ");
}

/// <summary>
/// Markdown for `docs/reference/environment-variables.md`.
/// </summary>
public static class EnvVarRenderer
{
    public static string Render(IReadOnlyList<EnvVarInfo> vars)
    {
        var sb = new StringBuilder();
        sb.AppendLine(IndexRenderer.AutoGenMarker);
        sb.AppendLine();
        sb.AppendLine("# Environment variables");
        sb.AppendLine();
        sb.AppendLine("Every environment-variable reference discovered in the source tree. Both the C# `Environment.GetEnvironmentVariable(\"…\")` read sites and the contributor scripts under `tools/` (`*.sh` and `*.ps1`) are scanned. Variables are grouped by name, so reads, writes, and defaults that all target the same variable appear together.");
        sb.AppendLine();
        if (vars.Count == 0)
        {
            sb.AppendLine("_No environment-variable references found in the current source tree._");
            sb.AppendLine();
            return sb.ToString();
        }

        // Group by variable name.
        var byName = vars
            .GroupBy(v => v.Name, StringComparer.Ordinal)
            .OrderBy(g => g.Key, StringComparer.Ordinal)
            .ToList();

        sb.AppendLine("## Summary");
        sb.AppendLine();
        sb.AppendLine("| Variable | Kinds | Default(s) |");
        sb.AppendLine("| --- | --- | --- |");
        foreach (var g in byName)
        {
            var kinds = string.Join(", ", g.Select(v => v.Kind).Distinct().OrderBy(k => k, StringComparer.Ordinal));
            var defaults = string.Join(", ", g.Where(v => !string.IsNullOrEmpty(v.FallbackLiteral))
                .Select(v => $"`{v.FallbackLiteral}`").Distinct());
            sb.AppendLine($"| `{g.Key}` | {kinds} | {defaults} |");
        }
        sb.AppendLine();

        sb.AppendLine("## Per-variable detail");
        sb.AppendLine();
        foreach (var g in byName)
        {
            sb.AppendLine($"### `{g.Key}`");
            sb.AppendLine();
            sb.AppendLine("| Kind | Source | Default / value | Context |");
            sb.AppendLine("| --- | --- | --- | --- |");
            foreach (var v in g)
            {
                var fallback = string.IsNullOrEmpty(v.FallbackLiteral) ? "" : $"`{v.FallbackLiteral}`";
                sb.AppendLine($"| `{v.Kind}` | [`{v.FileRelativePath}:{v.Line}`](https://github.com/TrakHound/MTConnect.NET/blob/master/{v.FileRelativePath}#L{v.Line}) | {fallback} | {Escape(v.Context)} |");
            }
            sb.AppendLine();
        }

        sb.AppendLine("Adding a new `Environment.GetEnvironmentVariable(\"…\")` call, a new `${MTCONNECT_…}` read in a contributor script, or a new `$env:MTCONNECT_…` reference in a PowerShell script without regenerating this page fails the validation test in CI.");
        sb.AppendLine();
        return sb.ToString();
    }

    private static string Escape(string s) => s.Replace("|", "\\|").Replace("\n", " ").Replace("\r", " ");
}

/// <summary>
/// Markdown for `docs/reference/configuration.md`.
/// </summary>
public static class ConfigRenderer
{
    public static string Render(IReadOnlyList<ConfigClassInfo> classes)
    {
        var sb = new StringBuilder();
        sb.AppendLine(IndexRenderer.AutoGenMarker);
        sb.AppendLine();
        sb.AppendLine("# Configuration schema");
        sb.AppendLine();
        sb.AppendLine("The agent and adapter accept YAML or JSON configuration. The schema below is derived from the source declarations of every option class — the `JsonPropertyName` / `YamlMember.Alias` value gives the on-the-wire key, and the `///` summary above each property is reproduced verbatim.");
        sb.AppendLine();
        sb.AppendLine("## Worked example");
        sb.AppendLine();
        sb.AppendLine("A minimal `agent.config.yaml` for an HTTP agent on port 5000:");
        sb.AppendLine();
        sb.AppendLine("```yaml");
        sb.AppendLine("observationBufferSize: 150000");
        sb.AppendLine("assetBufferSize: 1000");
        sb.AppendLine("defaultVersion: \"2.5\"");
        sb.AppendLine("enableAgentDevice: true");
        sb.AppendLine("enableMetrics: true");
        sb.AppendLine("");
        sb.AppendLine("modules:");
        sb.AppendLine("  - http:");
        sb.AppendLine("      port: 5000");
        sb.AppendLine("      documentFormat: xml");
        sb.AppendLine("```");
        sb.AppendLine();
        sb.AppendLine("## Option classes");
        sb.AppendLine();
        foreach (var c in classes)
        {
            sb.AppendLine($"### `{c.TypeName}`");
            sb.AppendLine();
            sb.AppendLine($"- **Namespace**: `{c.Namespace}`");
            sb.AppendLine($"- **Source**: [`{c.FileRelativePath}`](https://github.com/TrakHound/MTConnect.NET/blob/master/{c.FileRelativePath})");
            sb.AppendLine();
            if (!string.IsNullOrEmpty(c.Summary))
            {
                sb.AppendLine(c.Summary);
                sb.AppendLine();
            }
            sb.AppendLine("| Key | C# property | Type | Description |");
            sb.AppendLine("| --- | --- | --- | --- |");
            foreach (var p in c.Properties)
            {
                sb.AppendLine($"| `{p.SerialisedKey}` | `{p.Name}` | `{Escape(p.Type)}` | {Escape(p.Summary)} |");
            }
            sb.AppendLine();
        }
        return sb.ToString();
    }

    private static string Escape(string s) => s.Replace("|", "\\|").Replace("\n", " ").Replace("\r", " ");
}
